INSERT INTO categories (name, description, image_url, sort_order, "createdAt", "updatedAt") VALUES
('Чай', 'В чайной карте представлены чаи, классифицированные по степени ферментации. Белый, чёрный, зелёный, красный, жёлтый чаи или улуны и пуэры.', '/images/чай.jpg', 1, NOW(), NOW()),
('Чайные смеси', 'Раздел содержит травяные чаи и чайные смеси.', '/images/чайные_смеси.jpg', 2, NOW(), NOW()),
('Чайная утварь', 'Всё, что может понадобиться для чайной церемонии или просто удобного чаепития. Чайники, пиалы, гайвани, чахаи и многое другое.', '/images/чайная_утварь.jpg', 3, NOW(), NOW());
